# Homebrew cask for the cc-pool Notification Center widget (CCPoolStatus.app).
#
# The app is Developer ID signed, notarized, and stapled, so Gatekeeper
# validates it offline; the postflight strips Homebrew's download quarantine so
# the first launch is silent. Install with `ccp widget`, or by hand:
#
#   brew install --cask yasyf/tap/cc-pool-status
#
# This file is GENERATED by cc-pool's release.yml (render-formula) and
# pushed here on every tagged release — do not hand-edit; change the
# template at .github/cask/cc-pool-status.rb.tmpl in cc-pool instead.
cask "cc-pool-status" do
  version "0.43.1"
  sha256 "b42ca5818da6fc8905f5dc8ecc91e0a2c942abafc23647da125e5d1cdb74aa87" # app

  url "https://github.com/yasyf/cc-pool/releases/download/v#{version}/cc-pool-status-v#{version}-darwin.zip"
  name "cc-pool Status"
  desc "Notification Center widget showing cc-pool account status"
  homepage "https://github.com/yasyf/cc-pool"

  depends_on macos: :sonoma # parsed with a ">=" comparator: sonoma or newer
  depends_on formula: "cc-pool"

  app "CCPoolStatus.app"

  postflight do
    # Strip Homebrew's download quarantine so first launch is silent (notarized+stapled).
    system_command "/usr/bin/xattr",
                   args: ["-dr", "com.apple.quarantine", "#{appdir}/CCPoolStatus.app"],
                   must_succeed: false
    system_command "/usr/bin/open", args: ["-g", "#{appdir}/CCPoolStatus.app"], must_succeed: false
  end

  uninstall quit: "com.yasyf.cc-pool.status"

  zap trash: [
    "~/Library/Containers/com.yasyf.cc-pool.status.widget",
    "~/Library/Preferences/com.yasyf.cc-pool.status.plist", # login-item one-shot flag
  ]

  caveats <<~EOS
    Launch the app once so macOS discovers the widget:
      open -ga CCPoolStatus
    Then: Notification Center (click the menu-bar clock) → Edit Widgets → "cc-pool".

    For the File Provider overlay, run the guided setup:
      ccp fp onboard
    Health checks any time: ccp doctor
  EOS
end
